const item = $json;

const raw = item["Image URL"] || item.image_url || '';

const urls = raw
  .split(/[,\n]/)
  .map(u => u.trim())
  .filter(Boolean);

const image_urls = urls.length > 0 ? urls : (raw ? [raw] : []);

const primary_image_url = image_urls[0] || '';

return [
  {
    json: {
      ...item,
      image_urls,
      primary_image_url
    }
  }
];

return [{
  json: {
    ...$json,
    run_tiktok: true,
    run_instagram: false,
    run_youtube: false
  }
}];

const item = $json;

// raw string from sheet
const raw = item.image_url || item["Image URL"] || "";

// split into array
const urls = raw
  .split(/[\n,]/)
  .map(u => u.trim())
  .filter(Boolean);

// fallback
if (urls.length === 0) {
  return [{
    json: {
      ...item,
      current_image_url: null
    }
  }];
}

// expand
return urls.map(url => ({
  json: {
    ...item,
    current_image_url: url
  }
}));

